import React, { useState, useEffect } from 'react';

function App() {
  const [codigo, setCodigo] = useState("");

  // Função para processar o código quando o leitor der "Enter"
  const handleKeyDown = (e) => {
    if (e.key === 'Enter') {
      alert("Código lido: " + codigo);
      // Aqui depois faremos a busca no seu Banco de Dados (Backend)
      setCodigo(""); // Limpa para a próxima leitura
    }
  };

  return (
    <div style={{ textAlign: 'center', marginTop: '100px', fontFamily: 'Arial' }}>
      <h1>🚀 Sistema TSEA Online</h1>
      <p>Aproxime o leitor e faça o "BIP"</p>
      
      {/* O leitor precisa que este campo esteja selecionado (focado) */}
      <input 
        autoFocus 
        type="text" 
        value={codigo}
        onChange={(e) => setCodigo(e.target.value)}
        onKeyDown={handleKeyDown}
        placeholder="Aguardando scanner..."
        style={{
          padding: '10px',
          fontSize: '20px',
          borderRadius: '5px',
          border: '2px solid #0055ff',
          width: '300px',
          textAlign: 'center'
        }}
      />
      
      <p style={{ marginTop: '20px', color: '#666' }}>
        Dica: Se não funcionar, clique dentro da caixa azul e tente bipar novamente.
      </p>
    </div>
  );
}

export default App;
